def findWinner(N : int, X: List[int], Y: List[int], Z: List[int]) -> int:
    player_x = 0
    player_y = 0
    player_z = 0

    while True:
        if player_y >= N:
            if X[player_x] >= Z[player_z]:
                player_z += 1
                if player_z >= N:
                    return 0
            else:
                player_x += 1
                if player_x >= N:
                    return 2
        elif player_z >= N:
            if X[player_x] >= Y[player_y]:
                player_y += 1
                if player_y >= N:
                    return 0
            else:
                player_x += 1
                if player_x >= N:
                    return 1
        elif player_x >= N:
            if Y[player_y] >= Z[player_z]:
                player_z += 1
                if player_z >= N:
                    return 1
            else:
                player_y += 1
                if player_y >= N:
                    return 2
        else:
            if X[player_x] >= Y[player_y] and X[player_x] >= Z[player_z]:
                player_y += 1
                player_z += 1
                if player_y >= N and player_z >= N:
                    return 0
            elif Y[player_y] >= Z[player_z]:
                player_x += 1
                player_z += 1
                if player_x >= N and player_z >= N:
                    return 1
            else:
                player_x += 1
                player_y += 1
                if player_x >= N and player_y >= N:
                    return 2
